/**
 * `workflows` stage. Shows the suggested workflows, then once confirmed (or
 * if there are zero workflows) reveals the platform-connect picker. The
 * composer is an "Understood" CTA that dispatches `confirmWorkflows`.
 */

"use client";

import * as m from "motion/react-m";
import type { Dispatch } from "react";
import { useCallback, useEffect, useRef } from "react";
import ChatBubbleBot from "@/features/chat/components/bubbles/bot/ChatBubbleBot";
import { apiService } from "@/lib/api/service";
import { BOT_BUBBLE_DEFAULTS } from "../../constants/bubbleDefaults";
import { MOTION_FADE_UP, MOTION_FADE_UP_LARGE } from "../../constants/motion";
import type { Action, OnboardingState } from "../../state/types";
import { ComposerCTA } from "../ComposerCTA";
import { OnboardingCTAButton } from "../OnboardingCTAButton";
import { OnboardingPlatformConnect } from "../OnboardingPlatformConnect";
import { OnboardingWorkflowCards } from "../OnboardingWorkflowCards";

interface WorkflowsProps {
  state: OnboardingState;
  dispatch: Dispatch<Action>;
}

/**
 * True iff the platform-connect picker should be visible: either the user
 * acknowledged workflows or the backend produced none. Kept here so both
 * `Workflows` content and `WorkflowsComposer` agree.
 */
function shouldShowPlatformConnect(state: OnboardingState): boolean {
  const workflows = state.server?.suggested_workflows ?? [];
  return state.workflowsConfirmed || workflows.length === 0;
}

export function Workflows({ state, dispatch }: WorkflowsProps) {
  const popupCleanupRef = useRef<(() => void) | null>(null);

  const workflows = state.server?.suggested_workflows ?? [];
  const workflowsConfirmed = state.workflowsConfirmed;
  const showPlatformConnect = shouldShowPlatformConnect(state);

  const connectPlatform = useCallback(
    async (platform: string) => {
      popupCleanupRef.current?.();
      popupCleanupRef.current = null;

      const finish = () => {
        dispatch({ type: "platformConnected", platform });
      };

      try {
        const response = await apiService.get<{
          auth_url: string | null;
          auth_type: string;
          instructions: string | null;
          action_link: string | null;
        }>(`/platform-links/${platform.toLowerCase()}/connect`, {
          silent: true,
        });

        if (response.auth_url) {
          const width = 600;
          const height = 700;
          const left = window.screenX + (window.innerWidth - width) / 2;
          const top = window.screenY + (window.innerHeight - height) / 2;

          const popup = window.open(
            response.auth_url,
            `Connect ${platform}`,
            `width=${width},height=${height},left=${left},top=${top}`,
          );

          if (!popup) {
            finish();
            return;
          }

          let cancelled = false;
          let rafId = 0;
          const onMessage = (event: MessageEvent) => {
            if (event.source === popup) {
              cleanup();
              finish();
            }
          };
          const cleanup = () => {
            cancelled = true;
            if (rafId) cancelAnimationFrame(rafId);
            window.removeEventListener("message", onMessage);
            popupCleanupRef.current = null;
          };
          const tick = () => {
            if (cancelled) return;
            if (popup.closed) {
              cleanup();
              finish();
              return;
            }
            rafId = requestAnimationFrame(tick);
          };
          window.addEventListener("message", onMessage);
          rafId = requestAnimationFrame(tick);
          popupCleanupRef.current = cleanup;
        } else if (response.action_link) {
          window.open(response.action_link, "_blank");
          finish();
        }
      } catch {
        finish();
      }
    },
    [dispatch],
  );

  const skipPlatformConnect = useCallback(() => {
    dispatch({ type: "confirmWorkflows" });
  }, [dispatch]);

  useEffect(() => {
    return () => {
      popupCleanupRef.current?.();
      popupCleanupRef.current = null;
    };
  }, []);

  return (
    <m.div className="mt-4 space-y-4" {...MOTION_FADE_UP_LARGE}>
      {workflows.length > 0 && (
        <ChatBubbleBot
          {...BOT_BUBBLE_DEFAULTS}
          text="Here's what I set up to run on a recurring basis:"
        >
          <div className="mt-3">
            <OnboardingWorkflowCards workflows={workflows} />
          </div>
          {!workflowsConfirmed && (
            <p className="mt-2 ml-10.75 text-xs text-zinc-500">
              These run automatically. Customize them anytime in Workflows.
            </p>
          )}
        </ChatBubbleBot>
      )}

      {showPlatformConnect && (
        <m.div {...MOTION_FADE_UP}>
          <ChatBubbleBot
            {...BOT_BUBBLE_DEFAULTS}
            text="Get notifications and talk to me on the go:"
          >
            <div className="mt-3">
              <OnboardingPlatformConnect
                onConnect={connectPlatform}
                onSkip={skipPlatformConnect}
                connectedPlatform={state.connectedPlatform}
              />
            </div>
          </ChatBubbleBot>
        </m.div>
      )}
    </m.div>
  );
}

export function WorkflowsComposer({ state, dispatch }: WorkflowsProps) {
  if (shouldShowPlatformConnect(state)) return null;

  return (
    <ComposerCTA>
      <OnboardingCTAButton
        onClick={() => dispatch({ type: "confirmWorkflows" })}
      >
        Understood
      </OnboardingCTAButton>
    </ComposerCTA>
  );
}

async def _run_holo_card(
    user_id: str,
    user_doc: dict,
    profession: str,
    focus: str,
    triage_future: asyncio.Task[Optional[InboxTriage]],
    writing_style_future: asyncio.Task[Optional[WritingStyleProfile]],
    social_profiles_future: asyncio.Task[list[SocialProfile]],
) -> None:
    triage, writing_style, social_profiles = await asyncio.gather(
        triage_future, writing_style_future, social_profiles_future
    )

    t0 = time.monotonic()
    try:
        context_parts: list[str] = []
        if triage:
            context_parts.append(f"Inbox summary: {triage.summary}")
            if triage.patterns:
                context_parts.append(f"Inbox patterns: {'; '.join(triage.patterns)}")
            if triage.important_emails:
                senders = ", ".join(e.sender for e in triage.important_emails[:5])
                context_parts.append(f"Key contacts: {senders}")
        if writing_style:
            context_parts.append(f"Writing style: {writing_style.summary}")
        if social_profiles:
            platforms = ", ".join(f"{p.platform}: {p.url}" for p in social_profiles)
            context_parts.append(f"Social profiles: {platforms}")
        if focus:
            context_parts.append(f"Current focus: {focus}")
        context_summary = "\n".join(context_parts)

        metadata = await get_user_metadata(user_id, user=user_doc)
        card_design = generate_profile_card_design()
        phrase, bio_result = await asyncio.gather(
            generate_personality_phrase(user_id, context_summary, profession),
            generate_user_bio(user_id, context_summary, user=user_doc),
        )
        user_bio, bio_status = bio_result
        await save_personalization_data(
            user_id,
            card_design["house"],
            phrase,
            user_bio,
            bio_status,
            [],
            metadata["account_number"],
            metadata["member_since"],
            card_design["overlay_color"],
            card_design["overlay_opacity"],
        )
        log.info(
            f"[intelligence:timing] holo_card: {time.monotonic() - t0:.1f}s "
            f"(house={card_design['house']}, bio_status={bio_status})"
        )
    except Exception as e:
        log.error(f"[intelligence] holo_card failed: {e}", exc_info=True)

    await _emit_stage(user_id, OnboardingStage.HOLO_READY, {})


# ── Terminal helpers ─────────────────────────────────────────────────────────


async def _seed_conversation(user_id: str, first_message: str) -> Optional[str]:
    t0 = time.monotonic()
    try:
        cid = await seed_onboarding_conversation(
            user_id=user_id, first_message=first_message
        )
    except Exception as e:
        log.error(f"[intelligence] seed_conversation failed: {e}", exc_info=True)
        return None
    log.info(f"[intelligence:timing] seed_conversation: {time.monotonic() - t0:.1f}s")
    return cid


async def _persist_profiles(
    user_id: str,
    writing_style: Optional[WritingStyleProfile],
    triage: Optional[InboxTriage],
    social_profiles: list[SocialProfile],
) -> None:
    """Persist writing style, triage summary, and social profiles.

    Preserves two non-negotiable user-edit guards:
    - Writing style writes only sub-fields (never the whole object) so
      user_edited_summary is never clobbered.
    - Social profiles are only written if the user has not already confirmed
      them via POST /social-profiles ({"$exists": False} filter).
    """
    update_fields: dict = {}
    if writing_style:
        update_fields["onboarding.writing_style.summary"] = writing_style.summary
        update_fields["onboarding.writing_style.example"] = (
            writing_style.example.model_dump()
        )
    if triage:
        update_fields["onboarding.triage_summary"] = {
            "total_scanned": triage.total_scanned,
            "total_unread": triage.total_unread,
            "summary": triage.summary,
            "patterns": triage.patterns,
            "important_emails": [
                {
                    "sender": e.sender,
                    "subject": e.subject,
                    "why_important": e.why_important,
                }
                for e in triage.important_emails[:5]
            ],
        }

    if update_fields:
        try:
            await users_collection.update_one(
                {"_id": ObjectId(user_id)}, {"$set": update_fields}
            )
        except Exception as e:
            log.error(
                f"[intelligence] persist update_fields failed: {e}", exc_info=True
            )

    if social_profiles:
        try:
            # Only write auto-extracted profiles if the user hasn't already
            # confirmed them via POST /social-profiles.  The field may be
            # absent, null, or an empty list after initial onboarding — all
            # three mean "not yet confirmed by the user".
            await users_collection.update_one(
                {
                    "_id": ObjectId(user_id),
                    "$or": [
                        {"onboarding.social_profiles": {"$exists": False}},
                        {"onboarding.social_profiles": None},
                        {"onboarding.social_profiles": []},
                    ],
                },
                {
                    "$set": {
                        "onboarding.social_profiles": [
                            p.model_dump() for p in social_profiles
                        ]
                    }
                },
            )
        except Exception as e:
            log.error(
                f"[intelligence] persist social_profiles failed: {e}", exc_info=True
            )


