    def _append(self, key: str, message: str, **kwargs: Any) -> None:
        current = _wide_event.get() or {}
        entry: dict[str, Any] = {"msg": message, **kwargs}
        items = list(current.get(key, []))
        items.append(entry)
        _wide_event.set({**current, key: items})

